// Parse Slack interactive payload
const body = $input.first().json.body;
const payload = JSON.parse(body.payload);

// Case 1: Triggered via the "Translate this" menu shortcut
if (payload.type === 'message_action') {
  return {
    json: {
      text: payload.message.text,
      target_language: 'en', // Default to English for shortcuts
      source_language: 'auto',
      response_url: payload.response_url,
      user_id: payload.user.id,
      user_name: payload.user.name,
      trigger_type: 'shortcut'
    }
  };
}

// Case 2: Triggered via a button click (your current logic)
const value = payload.actions[0].value;
const parts = value.split('|');

return {
  json: {
    target_language: parts[0],
    source_language: parts[1],
    text: parts.slice(2).join('|'),
    response_url: payload.response_url,
    user_id: payload.user.id,
    user_name: payload.user.name,
    trigger_type: 'button'
  }
};

const response = $input.first().json.output;
const inputData = $node["📋 Parse Button Click"].json;

// Updated Flag Map: en is now US flag
const flags = {
  en: "🇺🇸", fr: "🇫🇷", es: "🇪🇸", de: "🇩🇪",
  he: "🇮🇱", ar: "🇸🇦", ja: "🇯🇵", zh: "🇨🇳",
  ru: "🇷🇺", it: "🇮🇹", pt: "🇵🇹", ko: "🇰🇷"
};

const langNames = {
  en: "English", fr: "French", es: "Spanish", de: "German",
  he: "Hebrew", ar: "Arabic", ja: "Japanese", zh: "Chinese",
  ru: "Russian", it: "Italian", pt: "Portuguese", ko: "Korean"
};

const rtlLangs = ["he", "ar"];

try {
  const start = response.indexOf('{');
  const end = response.lastIndexOf('}') + 1;
  if (start === -1 || end === 0) throw new Error("No JSON found");

  const parsed = JSON.parse(response.slice(start, end));
  let translation = parsed.translation || "(Translation missing)";

  if (rtlLangs.includes(inputData.target_language)) {
    translation = `\u202B${translation}\u202C`;
  }

  return {
    json: {
      detected_language_name: langNames[inputData.source_language] || inputData.source_language,
      target_language_name: langNames[inputData.target_language] || inputData.target_language,
      source_flag: flags[inputData.source_language] || "🌍",
      target_flag: flags[inputData.target_language] || "🌍",
      flag: flags[inputData.target_language] || "🌍", // Backward compatibility for existing blocks
      original_text: inputData.text,
      formatted_translation: translation,
      response_url: inputData.response_url
    }
  };
} catch (error) {
  return { json: { formatted_translation: "❌ Error: " + error.message, source_flag: "⚠️", target_flag: "⚠️" } };
}

// Extract data from Slack slash command
const body = $input.first().json.body;
const text = body.text ? body.text.trim() : 'No text provided';

return {
  json: {
    text: text,
    user_id: body.user_id || 'unknown',
    user_name: body.user_name || 'unknown',
    channel_id: body.channel_id || 'unknown',
    response_url: body.response_url || null
  }
};

